import React, { useEffect, useState } from "react";
import { Imgdb, Namedb } from "../components/firebase_setup";
import { v4 } from "uuid";
import { addDoc, collection, getDocs } from "firebase/firestore";
import { useNavigate } from "react-router-dom";
import { getDownloadURL, uploadBytes, ref } from "firebase/storage";


  /*adding id is something like,
  {
  "txtval": "John Doe",
  "imgUrl": "https://example.com/profilepic.jpg"
  "u_email": 
  }
  -->
  {
  "txtval": "John Doe",
  "imgUrl": "https://example.com/profilepic.jpg"
  "u_email": 
  id: 1123padi
  }
  */

function Feed() {
  console.log("This is the feed");
  const navigate = useNavigate();

  const [pdata, setPData] = useState([]);  //state to hold profile data, its a map
  //for posts
  const [postimg, setupostimg] = useState("");   //To get the pic, posted
  const [postData, setpostData] = useState([]); //state to hold post Data, its a map
  const [posttxt, setposttxt] = useState("");   //to get a normal text post
  const [textUpload, settextUpload] = useState(false); //to track text upload
  const [loading, setLoading] = useState(false); // To track loading status
  const [imgUploadComplete, setImgUploadComplete] = useState(false); // Track image upload status


  //handles uploading the Post Image
  const handlePimgUpload = (e) => {
    const file = e.target.files[0];
    setLoading(true);
    const PostimgRef = ref(Imgdb, `PostImgFile/${v4()}`); //unique path for the firebase storage

    uploadBytes(PostimgRef, file)
    .then(snapshot => getDownloadURL(snapshot.ref))
    .then(url => {
      setupostimg(url);
      setImgUploadComplete(true);
      setLoading(false);
      console.log("Post Image uploaded at:", url);
    })
    .catch(error => {             //if it doesnt rather than crashing it js gives a error
      console.error("Error uploading post image:", error);
      setLoading(false);          // Stop loading in case of error
    });
  }

  const handleInput = async () => {
    if (imgUploadComplete || textUpload) {
      try {
        const docRef = collection(Namedb, "PostData");
        await addDoc(docRef, {
          posttxtval: posttxt,
          postimgVal: postimg
        });
        console.log("Post Document successfully written!");
      } catch (error){
        console.log("Error Writing Post Document: ", error);
      }
    } else {
      console.log("Please wait for image to get uploaded");
    }
  }


  const getData = async() => {
    const dataref = collection(Namedb, "ProfileData");  //References to the Collection "ProfileData" in FireStore Collection
    const profileDb = await getDocs(dataref);           //Retrives the data from "ProfileData" in Firestore Collection
    const retrivePData = profileDb.docs.map(val=>({...val.data(), id:val.id}));  //maps over document. gets the Data(txtval, imgurl, email). then adds a document id to that data
    setPData(retrivePData);                             //updates it to the gotten data.
  }

  //getting the profile data using getData() when the page runs
    useEffect(()=>{
      getData()                                           //runs the getData() when mounted. 
    })
    console.log(pdata,"firedataP");

  //to handle log out
  const handleLogout = () => {
    localStorage.clear();
    navigate("/SignIn");
  };


  //below it kinda just maps through gets the id and for that specific, it shows that profile pic(uploaded img) and profile Name(uploaded Name)
  return (
    <div className="Feed">
        <h1 className="Feed_header"> Catsa </h1>
        
        <div className="Post_info">
      
          <input 
            className="Post_txt"
            placeholder="MAKE YOUR POST!!"
            onChange={ (e) => setposttxt(e.target.value) && settextUpload(true) }
            value={posttxt}
        /><br/>

          <input
            className="Post_Img"
            type = "file"
            placeholder="UPLOAD YOUR POST!!"
            onChange={handlePimgUpload}
            disabled = {loading}
          />

        </div>

        <button
        className="PostAdd"
        onClick={handleInput}
        disabled = {!imgUploadComplete || !textUpload || loading}>
          {loading ? "Uploading..." : "POST"}
        </button>

        <div className="Profile_info">
            {
              pdata.map(value => <div>
                <p> Profile Name: {value.txtval}</p><br/><br/>
                <p> Profile Pic: </p>
                <img src={value.imgUrl}/>
                </div>)
            }
        </div>

        <br/><br/>

        <button 
        className="Logoutbut" 
        onClick={handleLogout}>
            Logout
        </button>

    </div>

    
  );
}

export default Feed;
